import{_ as a,o as t,c as n,ag as o}from"./chunks/framework.DXGyWiRo.js";const c=JSON.parse('{"title":"Ending a Game","description":"","frontmatter":{},"headers":[],"relativePath":"scoring-games/ending-a-game.md","filePath":"scoring-games/ending-a-game.md"}'),s={name:"scoring-games/ending-a-game.md"};function i(r,e,l,m,d,h){return t(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="ending-a-game" tabindex="-1">Ending a Game <a class="header-anchor" href="#ending-a-game" aria-label="Permalink to &quot;Ending a Game&quot;">​</a></h1><h2 id="end-the-game-session" tabindex="-1">End the Game Session <a class="header-anchor" href="#end-the-game-session" aria-label="Permalink to &quot;End the Game Session&quot;">​</a></h2><p>When the game is over:</p><ol><li>From the Game Hub tap <strong>End Game</strong></li><li>A confirmation screen appears asking you to verify the final score</li><li>Confirm the result — Win, Loss, or Tie is calculated automatically from the scores</li><li>Tap <strong>Confirm</strong> to end the session</li></ol><h2 id="what-happens-when-you-end-a-game" tabindex="-1">What Happens When You End a Game <a class="header-anchor" href="#what-happens-when-you-end-a-game" aria-label="Permalink to &quot;What Happens When You End a Game&quot;">​</a></h2><ul><li>The game session status changes from Active to Complete</li><li>The final score and result are saved to your schedule</li><li>Your season record on the dashboard updates</li><li>The active game banner disappears from all screens</li><li>All logged stats remain associated with this game</li></ul><h2 id="resuming-an-interrupted-game" tabindex="-1">Resuming an Interrupted Game <a class="header-anchor" href="#resuming-an-interrupted-game" aria-label="Permalink to &quot;Resuming an Interrupted Game&quot;">​</a></h2><p>If you navigate away from the game mid-session the session remains active. You can return to scoring from:</p><ul><li>The <strong>amber active game banner</strong> that appears at the top of every screen</li><li>The <strong>Resume button</strong> on the active game card in your schedule</li><li>The <strong>Live Game widget</strong> at the top of your dashboard</li></ul><p>The game session does not end until you explicitly tap End Game.</p><h2 id="retroactive-scoring" tabindex="-1">Retroactive Scoring <a class="header-anchor" href="#retroactive-scoring" aria-label="Permalink to &quot;Retroactive Scoring&quot;">​</a></h2><p>If you could not score a game live you can enter stats later:</p><ol><li>From the Game Hub tap <strong>Start New Session</strong></li><li>Select <strong>Unscored Past Games</strong> — any scheduled game without stats appears here</li><li>Select the game and log stats from video or memory</li><li>End the session normally when complete</li></ol>',13)])])}const u=a(s,[["render",i]]);export{c as __pageData,u as default};
